{
  "grammar": [
    {
      "pattern": "在 + location + 的 + 旁邊 / 對面 / 前面 / 後面 / 左邊 / 右邊 / 中間",
      "structure": ["在", "location", "的", "relative position"],
      "explanation_en": "Use '在' to indicate a location, then add a relative position word to specify where something is relative to that location.",
      "title": "Using 在 with Relative Positions",
      "meaning": "Indicating location with relative position",
      "when_to_use": ["When describing where an object or place is located inside a building", "When giving directions to find a specific spot"],
      "when_not_to_use": ["When the location is already clear without a reference point", "When using absolute directions like north/south"],
      "pragmatic_notes": "In Taiwan, people often use landmarks like 櫃台 or 電梯 as reference points. It's polite to point or gesture while speaking.",
      "word_order_notes": "The structure is fixed: 在 + reference location + 的 + relative position. Do not reverse the order.",
      "english_contrast": "English says 'next to the counter' but Chinese says '在櫃台的旁邊' (at counter's side).",
      "korean_contrast": "Korean uses '~의 옆에' similar to Chinese '的旁邊', but word order may differ.",
      "negative_examples": [
        {
          "text": "洗手間在旁邊櫃台",
          "error": "Missing 的 between 櫃台 and 旁邊; should be 櫃台的旁邊"
        }
      ],
      "incorrect_examples": [
        {
          "text": "電梯在左邊櫃台",
          "error": "Should be 櫃台的左邊, not 左邊櫃台"
        }
      ],
      "transformation_drills": ["Change '洗手間在櫃台的旁邊' to use 對面", "Change '出口在電梯的前面' to use 後面"],
      "production_drills": ["Describe where the bathroom is using 在 and 旁邊", "Tell someone the elevator is to the left of the counter"],
      "common_error_patterns": ["Omitting 的 between location and position word", "Reversing the order of location and position"],
      "repair_feedback": {
        "word_order": "Remember: 在 + place + 的 + position word, e.g., 在櫃台的旁邊",
        "politeness": "Add 請問 at the beginning for polite questions",
        "vocabulary": "Use correct position words like 旁邊, 對面, 左邊"
      }
    },
    {
      "pattern": "Location word + 在 + 哪裡？ / 在 + location word + 嗎？",
      "structure": ["location word", "在", "question word or phrase"],
      "explanation_en": "Use location words like 洗手間, 電梯, 出口, 櫃台, 教室 with 在 to ask or state where they are.",
      "title": "Asking About Locations with 在",
      "meaning": "Asking where a place is",
      "when_to_use": ["When you need to find a specific place inside a building", "When confirming if a place is at a certain location"],
      "when_not_to_use": ["When asking about people or objects (use different structure)", "When the location is obvious"],
      "pragmatic_notes": "In Taiwan, it's common to ask 請問洗手間在哪裡？ with a polite tone. Pointing or looking around is natural.",
      "word_order_notes": "The location word comes first, then 在, then the question. Do not put 在 before the location word.",
      "english_contrast": "English says 'Where is the bathroom?' but Chinese says '洗手間在哪裡？' (bathroom at where?).",
      "korean_contrast": "Korean uses '화장실이 어디에 있어요?' similar structure but with different particles.",
      "negative_examples": [
        {
          "text": "在哪裡洗手間？",
          "error": "Location word should come before 在, not after"
        }
      ],
      "incorrect_examples": [
        {
          "text": "電梯在嗎？",
          "error": "This asks if the elevator exists, not where it is; use 在哪裡 for location"
        }
      ],
      "transformation_drills": ["Change '洗手間在哪裡？' to a yes/no question with 嗎", "Change '出口在櫃台旁邊嗎？' to a where question"],
      "production_drills": ["Ask where the elevator is", "Ask if the classroom is on the second floor"],
      "common_error_patterns": ["Putting 在 before the location word in questions", "Using 在嗎？ when meaning to ask location"],
      "repair_feedback": {
        "word_order": "Place the location word first: 洗手間在哪裡？",
        "politeness": "Always start with 請問 for polite inquiries",
        "vocabulary": "Use correct location words like 洗手間, 電梯, 出口"
      }
    },
    {
      "pattern": "從 + place A + 到 + place B + (怎麼走？ / 直走 / 左轉 / 右轉)",
      "structure": ["從", "place A", "到", "place B", "direction or question"],
      "explanation_en": "Use 從 (from) and 到 (to) to describe a route from one place to another, often with directions like 直走, 左轉, 右轉.",
      "title": "Giving Directions with 從 and 到",
      "meaning": "Describing a route from one place to another",
      "when_to_use": ["When giving step-by-step directions inside a building", "When asking how to get from one point to another"],
      "when_not_to_use": ["When the destination is very close without need for route", "When using only one location without movement"],
      "pragmatic_notes": "In Taiwan, people often combine 從...到... with 然後 and 再 for multiple steps. Use 請 at the beginning for polite requests.",
      "word_order_notes": "The order is fixed: 從 + start point + 到 + end point. Directions come after 到.",
      "english_contrast": "English says 'from the counter to the elevator' but Chinese says '從櫃台到電梯' (from counter to elevator).",
      "korean_contrast": "Korean uses '~에서 ~까지' similar to 從...到..., but word order may differ.",
      "negative_examples": [
        {
          "text": "到櫃台從電梯怎麼走？",
          "error": "Should be 從電梯到櫃台, not reversed"
        }
      ],
      "incorrect_examples": [
        {
          "text": "從洗手間到教室左轉",
          "error": "Missing 怎麼走 or a clear direction; should be 從洗手間到教室怎麼走？ or 從洗手間到教室，然後左轉"
        }
      ],
      "transformation_drills": ["Change '從櫃台到電梯怎麼走？' to include 直走 and 左轉", "Change '從一樓到三樓' to a question form"],
      "production_drills": ["Ask how to get from the counter to the bathroom", "Give directions from the elevator to the exit using 從...到..."],
      "common_error_patterns": ["Reversing 從 and 到", "Omitting 怎麼走 when asking for directions"],
      "repair_feedback": {
        "word_order": "Always start with 從 + start, then 到 + end: 從櫃台到電梯",
        "politeness": "Add 請問 at the beginning for polite questions",
        "vocabulary": "Use direction words like 直走, 左轉, 右轉 after 到"
      }
    }
  ]
}
